mapper.select:
select

,e.exam_name as examName
,k.kecheng_name as kechengName
,y.yonghu_name as yonghuName
,j.jiaoshi_name as jiaoshiName
from exam_record a
left join exam e on a.exam_id = e.id
left join kecheng k on a.kecheng_id = k.id
left join yonghu y on a.yonghu_id = y.id
left join jiaoshi j on e.jiaoshi_id = j.id


        and a.exam_id = #{params.examId}


        and a.kecheng_id = #{params.kechengId}


        and a.yonghu_id = #{params.yonghuId}


        and a.record_status = #{params.recordStatus}


        and a.pass_status = #{params.passStatus}


        and e.jiaoshi_id = #{params.jiaoshiId}


order by a.${params.sort} ${params.order}
